const question = $.input.question;
const stopWords = ['what','is','the','a','an','how','does','do','can','where','when','which','who','why','are','was','were','been','being','have','has','had','will','would','should','could','may','might','shall','about','into','through','during','before','after','above','below','from','with','this','that','these','those','for','and','but','or'];
const keywords = question.split(/\s+/).filter(w => w.length > 2 && !stopWords.includes(w.toLowerCase())).slice(0, 5).join(' ');

let q = "trashed=false and mimeType != 'application/vnd.google-apps.folder'";
if (keywords) q += " and fullText contains '" + keywords.replace(/'/g, '') + "'";
const folderId = $.input.folderId || '';
if (folderId) q += " and '" + folderId + "' in parents";

return { searchQuery: q, keywords };

const files = ($.steps.searchFiles.response.files || []).slice(0, 5);
const exportable = files.map(f => ({
  id: f.id,
  name: f.name,
  mimeType: f.mimeType,
  modifiedTime: f.modifiedTime,
  isGoogleDoc: (f.mimeType || '').startsWith('application/vnd.google-apps.')
}));

return { files: exportable, fileCount: exportable.length };

const files = $.steps.selectFiles.output.files;
const iterations = $.steps.fetchContent.response.iterations || [];

let compiled = '';
files.forEach((file, i) => {
  compiled += '=== DOCUMENT ' + (i + 1) + ': ' + file.name + ' ===\n';
  compiled += 'Type: ' + file.mimeType + ' | Modified: ' + (file.modifiedTime || 'unknown') + '\n\n';

  const iter = iterations[i];
  if (iter && iter.exportFile && iter.exportFile.response) {
    const resp = iter.exportFile.response;
    const text = typeof resp === 'string' ? resp : (resp.body || resp.data || JSON.stringify(resp));
    compiled += (typeof text === 'string' ? text : JSON.stringify(text)).slice(0, 5000) + '\n';
  } else {
    compiled += '(content not available)\n';
  }
  compiled += '\n\n';
});

return { compiled: compiled.slice(0, 30000), fileCount: files.length, fileNames: files.map(f => f.name) };

const d = $.steps.compileDocuments.output;
const question = $.input.question;

let prompt = 'You are a document analysis assistant. Answer the following question accurately using ONLY the content from the Google Drive documents provided below. If the answer is not in the documents, say so.\n\n';
prompt += 'QUESTION: ' + question + '\n\n';
prompt += 'DOCUMENTS (' + d.fileCount + ' files found):\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Answer based ONLY on the document content provided\n';
prompt += '- Cite which document(s) the information comes from using [Doc N: filename] notation\n';
prompt += '- If information is found across multiple documents, synthesize it\n';
prompt += '- If the answer is not found, clearly state that\n';
prompt += '- Use Slack mrkdwn: *bold* (NOT **bold**), _italic_, numbered lists\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "comprehensive answer citing [Doc N: filename] sources",\n';
prompt += '  "confidence": "high|medium|low",\n';
prompt += '  "documentsUsed": [{ "number": 1, "name": "filename", "relevance": "how relevant" }],\n';
prompt += '  "keyExtracts": ["important quote or data point from the documents"],\n';
prompt += '  "followUpQuestions": ["related question to explore further"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'medium', documentsUsed: [], keyExtracts: [], followUpQuestions: [] }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const fileCount = $.steps.compileDocuments.output.fileCount;

const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Document Q&A Answer', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: confidenceEmoji + ' *Confidence:* ' + (ai.confidence || 'medium') + ' | *Documents searched:* ' + fileCount } });
blocks.push({ type: 'divider' });

const answer = (ai.answer || 'No answer generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answer } });
blocks.push({ type: 'divider' });

if (ai.keyExtracts && ai.keyExtracts.length > 0) {
  let kText = '*Key Extracts:*\n';
  ai.keyExtracts.forEach((k, i) => { kText += '> ' + k + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kText.slice(0, 2900) } });
}

if (ai.documentsUsed && ai.documentsUsed.length > 0) {
  let srcText = '*Sources:*\n';
  ai.documentsUsed.forEach(d => {
    srcText += '[Doc ' + d.number + '] *' + d.name + '* - ' + d.relevance + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 2900) } });
}

if (ai.followUpQuestions && ai.followUpQuestions.length > 0) {
  let fqText = '*Follow-up questions:*\n';
  ai.followUpQuestions.forEach((q, i) => { fqText += (i + 1) + '. ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fqText } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Drive + Claude AI | One CLI' }] });

const fallback = 'Document Q&A: ' + question.slice(0, 80) + ' (' + fileCount + ' docs searched)';
return { blocks, fallback };
